import { GoogleGenAI } from "@google/genai";

// Initialize the Google GenAI SDK using the API key exclusively from environment variables.
// Always use the named parameter `apiKey` as per guidelines.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateProjectDescription = async (title: string, category: string): Promise<string> => {
  try {
    // Updated to 'gemini-3-flash-preview' for basic text tasks (summarization/Q&A/description generation).
    const model = 'gemini-3-flash-preview';

    const prompt = `
      Act as a Lead Creative Director for a high-end avant-garde production studio. 
      Write a sophisticated, evocative, and texturally rich description (2-3 sentences) for a film project.

      Project Details:
      - Title: "${title}"
      - Category: "${category}"

      Directives:
      1. Analyze the keywords in the Title to derive specific visual imagery.
      2. Focus strictly on cinematic atmosphere, lighting, texture, and emotional resonance.
      3. Avoid generic openers. Dive directly into the imagery.
      4. The tone must be artistic, mysterious, and expensive.
    `;

    // Query GenAI with both the model name and prompt directly in `ai.models.generateContent`.
    const response = await ai.models.generateContent({
      model: model,
      contents: prompt,
    });

    // Directly access the `.text` property to get the generated content (it is not a method).
    return response.text?.trim() || "A visual exploration of narrative depth, weaving together light and texture to create an immersive cinematic experience.";
  } catch (error) {
    console.error("Error generating description:", error);
    return "A visual exploration of narrative depth, weaving together light and texture to create an immersive cinematic experience.";
  }
};
